-- Signal Outcomes Tracking Schema for War Machine\n-- Run this SQL file against your Railway PostgreSQL database\n\n-- Main signal outcomes table\nCREATE TABLE IF NOT EXISTS signal_outcomes (\n    id SERIAL PRIMARY KEY,\n    ticker VARCHAR(10) NOT NULL,\n    signal_time TIMESTAMP NOT NULL,\n    pattern VARCHAR(50) NOT NULL,\n    confidence DECIMAL(5,2),\n    \n    -- Entry/Exit data\n    entry_price DECIMAL(10,2) NOT NULL,\n    stop_loss DECIMAL(10,2) NOT NULL,\n    target_1 DECIMAL(10,2) NOT NULL,\n    target_2 DECIMAL(10,2) NOT NULL,\n    exit_price DECIMAL(10,2),\n    exit_time TIMESTAMP,\n    \n    -- Outcome tracking\n    outcome VARCHAR(20), -- WIN, LOSS, BREAKEVEN\n    hit_t1 BOOLEAN DEFAULT FALSE,\n    hit_t2 BOOLEAN DEFAULT FALSE,\n    stopped_out BOOLEAN DEFAULT FALSE,\n    \n    -- Performance metrics\n    profit_pct DECIMAL(10,4),\n    profit_r DECIMAL(10,4), -- Profit in R multiples\n    hold_minutes INTEGER,\n    \n    -- Context features for ML\n    regime VARCHAR(20), -- TRENDING, EXPLOSIVE, REVERSAL\n    vix_level DECIMAL(5,2),\n    spy_trend VARCHAR(20),\n    rvol DECIMAL(5,2),\n    score DECIMAL(5,2),\n    explosive_override BOOLEAN DEFAULT FALSE,\n    \n    created_at TIMESTAMP DEFAULT NOW()\n);\n\n-- Pattern performance aggregate table\nCREATE TABLE IF NOT EXISTS pattern_performance (\n    pattern VARCHAR(50) PRIMARY KEY,\n    total_trades INTEGER DEFAULT 0,\n    wins INTEGER DEFAULT 0,\n    losses INTEGER DEFAULT 0,\n    win_rate DECIMAL(5,2),\n    avg_profit_pct DECIMAL(10,4),\n    avg_hold_minutes INTEGER,\n    updated_at TIMESTAMP DEFAULT NOW()\n);\n\n-- ML training data table\nCREATE TABLE IF NOT EXISTS ml_training_data (\n    id SERIAL PRIMARY KEY,\n    signal_id INTEGER REFERENCES signal_outcomes(id),\n    \n    -- Features\n    rvol DECIMAL(5,2),\n    vix DECIMAL(5,2),\n    score DECIMAL(5,2),\n    time_of_day VARCHAR(5), -- HH:MM format\n    confidence DECIMAL(5,2),\n    regime VARCHAR(20),\n    \n    -- Target\n    outcome BOOLEAN, -- TRUE = WIN, FALSE = LOSS\n    profit_r DECIMAL(10,4),\n    \n    created_at TIMESTAMP DEFAULT NOW()\n);\n\n-- Indexes for faster queries\nCREATE INDEX IF NOT EXISTS idx_signal_time ON signal_outcomes(signal_time);\nCREATE INDEX IF NOT EXISTS idx_ticker ON signal_outcomes(ticker);\nCREATE INDEX IF NOT EXISTS idx_pattern ON signal_outcomes(pattern);\nCREATE INDEX IF NOT EXISTS idx_outcome ON signal_outcomes(outcome);\n\n-- Bootstrap data: Add today's NVDA winner as first training example\nINSERT INTO signal_outcomes (\n    ticker, signal_time, pattern, confidence,\n    entry_price, stop_loss, target_1, target_2,\n    exit_price, exit_time,\n    outcome, hit_t1, hit_t2, stopped_out,\n    profit_pct, profit_r, hold_minutes,\n    regime, vix_level, spy_trend, rvol, score, explosive_override\n) VALUES (\n    'NVDA',\n    '2026-03-04 09:40:00',\n    'EXPLOSIVE_BREAKOUT',\n    60.0,\n    181.61,\n    180.16, -- -0.80% stop\n    185.24, -- +2.00% T1\n    187.42, -- +3.20% T2\n    184.50, -- Hypothetical exit at T1\n    '2026-03-04 10:01:00',\n    'WIN',\n    TRUE,\n    FALSE,\n    FALSE,\n    1.59, -- +1.59% profit\n    1.99, -- 1.99R profit\n    21, -- 21 minute hold\n    'EXPLOSIVE',\n    22.4,\n    'BULLISH',\n    4.0,\n    87.5,\n    TRUE\n)\nON CONFLICT DO NOTHING; -- Prevent duplicate if already exists\n\n-- Add to pattern performance\nINSERT INTO pattern_performance (pattern, total_trades, wins, losses, win_rate, avg_profit_pct, avg_hold_minutes)\nVALUES ('EXPLOSIVE_BREAKOUT', 1, 1, 0, 100.0, 1.59, 21)\nON CONFLICT (pattern) DO NOTHING;\n\n-- Add to ML training data\nINSERT INTO ml_training_data (signal_id, rvol, vix, score, time_of_day, confidence, regime, outcome, profit_r)\nSELECT \n    id,\n    4.0,\n    22.4,\n    87.5,\n    '09:40',\n    60.0,\n    'EXPLOSIVE',\n    TRUE,\n    1.99\nFROM signal_outcomes\nWHERE ticker = 'NVDA' AND signal_time = '2026-03-04 09:40:00'\nON CONFLICT DO NOTHING;\n\nSELECT 'Signal Outcomes schema created successfully!' as status;\n